function normalizeText(value) {
  return String(value || "").toLowerCase().replace(/\s+/g, " ").trim();
}

function wordCount(value) {
  const text = String(value || "").trim();
  if (!text) return 0;
  return text.split(/\s+/).length;
}

function containsKeyword(value, keyword) {
  const hay = normalizeText(value);
  const needle = normalizeText(keyword);
  if (!needle) return false;
  return hay.includes(needle);
}

function extractStrings(updates) {
  const out = [];
  for (const update of updates) {
    const fields = update?.fields || {};
    for (const key of Object.keys(fields)) {
      const value = fields[key];
      if (typeof value === "string") {
        const trimmed = value.trim();
        if (trimmed) out.push({ key, value: trimmed });
      }
    }
  }
  return out;
}

function splitSentences(text) {
  return String(text || "")
    .replace(/\s+/g, " ")
    .split(/[.!?]\s+/)
    .map(s => s.trim())
    .filter(s => s.length >= 16);
}

function detectDuplicateSentences(strings) {
  const seen = new Set();
  for (const { value } of strings) {
    const sentences = splitSentences(value);
    for (const s of sentences) {
      const n = normalizeText(s);
      if (!n) continue;
      if (seen.has(n)) return true;
      seen.add(n);
    }
  }
  return false;
}

function detectDuplicateFields(strings) {
  const seen = new Set();
  for (const { value } of strings) {
    const n = normalizeText(value);
    if (!n) continue;
    if (seen.has(n)) return true;
    seen.add(n);
  }
  return false;
}

function detectCityRepeatInHeadings(strings, cityRegion) {
  if (!cityRegion) return false;
  const city = normalizeText(cityRegion);
  let count = 0;
  for (const { key, value } of strings) {
    if (!/heading|headline|trust_heading|cta_headline/i.test(key)) continue;
    if (normalizeText(value).includes(city)) count += 1;
  }
  return count > 1;
}

function detectInYourArea(strings, pageType) {
  if (pageType === 'service_area') return false;
  for (const { value } of strings) {
    if (/\bin your area\b/i.test(value)) return true;
  }
  return false;
}


function detectForbiddenTokens(strings) {
  const patterns = [/PRIMARY_KEYWORD/i, /BUSINESS_NAME/i, /CITY_REGION/i, /\bNICHE_TOKEN\b/i];
  for (const { value } of strings) {
    for (const re of patterns) {
      if (re.test(value)) return true;
    }
  }
  return false;
}

function detectGenericPhrases(strings) {
  const patterns = [
    /delivers tailored solutions/i,
    /clear communication, clean execution/i,
    /long-?lasting results/i,
    /fast response and clear pricing/i,
    /upfront pricing before work starts/i,
    /trusted local team/i
  ];
  for (const { value } of strings) {
    for (const re of patterns) {
      if (re.test(value)) return true;
    }
  }
  return false;
}

