}
function shuffle(arr, seed) {
  const a = Array.isArray(arr) ? [...arr] : [];
  let s = Math.max(1, seed | 0);
  for (let i = a.length - 1; i > 0; i--) {
    s ^= (s << 13); s ^= (s >> 17); s ^= (s << 5);
    const j = Math.abs(s) % (i + 1);
    const tmp = a[i]; a[i] = a[j]; a[j] = tmp;
  }
  return a;
}

