  const suffix = attempt > 1 ? ` (${attempt})` : '';
  return `This page focuses on ${topic}${biz}${city}${suffix}.`;
}

function applyUniquenessGuard(updates) {
  const globalSeen = {};
  const pageSeen = {};
  let changedCount = 0;

  for (const update of updates) {
    if (String(update?.target || '') !== 'post_meta') continue;
    const postId = String(update?.id || '').trim();
    if (!postId) continue;
    if (!pageSeen[postId]) pageSeen[postId] = new Set();
    const ctx = postContextById[postId] || {};
    const fields = update?.fields && typeof update.fields === 'object' ? update.fields : {};

    for (const key of Object.keys(fields)) {
      const value = fields[key];
      if (typeof value !== 'string') continue;
      if (!shouldEnforceUniqueness(key)) continue;

      let nextVal = value;
      if (isHeadingKey(key) && isGenericHeadingValue(nextVal, ctx)) {
        nextVal = buildSpecificHeading(nextVal, ctx);
      }

      let norm = normalizeText(nextVal);
      if (!norm) {
        fields[key] = nextVal;
        continue;
      }

      const seenInPage = pageSeen[postId].has(norm);
      const seenAcross = globalSeen[norm] && globalSeen[norm] !== postId;

      if (seenInPage || seenAcross) {
        let attempt = 1;
        const isRich = /<p[\s>]|<ul[\s>]|<ol[\s>]/i.test(nextVal);
        const isList = !isRich && nextVal.includes('\n');
        let candidate = nextVal;
        let candidateNorm = norm;

        do {
          const sentence = buildUniqueSentence(ctx, postId, attempt);
          if (isList) {
            candidate = `${nextVal}\n${sentence}`;
          } else if (isRich) {
            candidate = `${nextVal}<p>${sentence}</p>`;
          } else if (isHeadingKey(key)) {
            candidate = `${nextVal} — ${sentence.replace(/\.$/, '')}`;
          } else {
            candidate = `${nextVal} ${sentence}`;
          }
          candidateNorm = normalizeText(candidate);
          attempt += 1;
        } while ((pageSeen[postId].has(candidateNorm) || (globalSeen[candidateNorm] && globalSeen[candidateNorm] !== postId)) && attempt < 4);

        nextVal = candidate;
        norm = candidateNorm;
        changedCount += 1;
      }

      fields[key] = nextVal;
      if (norm) {
        pageSeen[postId].add(norm);
        globalSeen[norm] = postId;
      }
    }

    update.fields = fields;
  }

  if (changedCount > 0) {
    warnings.push(`Uniqueness guard adjusted ${changedCount} field(s) to avoid duplicate content.`);
  }

  return updates;
}

for (const item of items) {
  const json = item.json || {};
  if (json.request_id) requestId = json.request_id;
  if (json.ok === false) hadFailure = true;
  if (Array.isArray(json.quality_warnings)) warnings.push(...json.quality_warnings);
  if (Array.isArray(json.updates)) mergedUpdates = mergedUpdates.concat(json.updates);
  const pageType = String(json.page_type || '').trim();
  if (pageType) pageTypeCounts[pageType] = (pageTypeCounts[pageType] || 0) + 1;
  if (json.page_type || json.blueprint_index !== undefined) {
    const key = String(json.blueprint_index ?? pageTypeCounts[pageType] ?? '');
