const webhook = $node["Webhook"].json || {};
const webhookPayload = webhook.body ?? webhook;
const jobId = webhook.job_id || webhook.body?.job_id || $json?.job_id || null;
const callbackUrl = webhook.callback_url || webhook.body?.callback_url || $json?.callback_url || "";
const requestId = webhook.body?.request_id || webhook.request_id || $json?.request_id || "";
const authHeader = webhookPayload.callback_authorization || webhook.body?.callback_authorization || webhook.headers?.authorization || webhook.headers?.Authorization || "";

const candidateRows = Array.isArray(webhookPayload.media_library_candidates)
  ? webhookPayload.media_library_candidates
  : [];
const imageGeneration = (webhookPayload && typeof webhookPayload.image_generation === 'object' && webhookPayload.image_generation) ? webhookPayload.image_generation : {};
const imageTargets = Array.isArray(imageGeneration.targets) ? imageGeneration.targets : [];
const mediaAnnotations = Array.isArray($json?.media_annotations)
