const qualityWarnings = Array.isArray($json?.quality_warnings) ? [...$json.quality_warnings] : [];

function fallbackAnnotationsFromTargets(targets, candidates) {
  if (!Array.isArray(targets) || targets.length === 0 || !Array.isArray(candidates) || candidates.length === 0) {
    return [];
  }
  const used = new Set();
  const scoreCandidate = (target, candidate) => {
    const haystack = [candidate.filename, candidate.title, candidate.alt, candidate.caption].filter(Boolean).join(' ').toLowerCase();
    if (!haystack) return 0;
    const sectionType = String(target.section_type || '').toLowerCase();
    const slot = String(target.slot || '').toLowerCase();
    let score = 0;
    if (slot && haystack.includes(slot)) score += 5;
    if (sectionType && haystack.includes(sectionType)) score += 4;
    const ctx = target.context && typeof target.context === 'object' ? target.context : {};
    ['city','niche','service_slug','area_slug','page_type'].forEach((key) => {
      const term = String(ctx[key] || '').toLowerCase().trim();
      if (term && haystack.includes(term)) score += 2;
    });
    return score;
  };

  const out = [];
  for (const target of targets) {
    if (!target || typeof target !== 'object') continue;
    const available = candidates
      .map((row) => ({ row, id: Number(row?.attachment_id || 0) }))
      .filter((x) => x.id > 0 && !used.has(x.id));
    if (available.length === 0) break;
    available.sort((a, b) => scoreCandidate(target, b.row) - scoreCandidate(target, a.row));
    const pick = available[0];
    used.add(pick.id);
    const sectionType = String(target.section_type || 'section');
    const slot = String(target.slot || 'image');
    const ctx = target.context && typeof target.context === 'object' ? target.context : {};
    const city = String(ctx.city || '').trim();
    const niche = String(ctx.niche || '').trim();
    const phrase = [sectionType, slot, city ? `in ${city}` : '', niche ? `for ${niche}` : ''].filter(Boolean).join(' ');
    const safeFile = `${sectionType}-${slot}${city ? `-${city}` : ''}`
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '') || 'site-image';

    out.push({
      attachment_id: pick.id,
      title: `${sectionType} ${slot}`.replace(/[_-]+/g, ' ').replace(/\b\w/g, (m) => m.toUpperCase()),
      alt_text: phrase,
      caption: phrase,
      description: `Photo reference used for ${phrase}.`,
      keywords: [sectionType, slot, city, niche].filter(Boolean),
      recommended_filename: `${safeFile}.jpg`
    });
  }
  return out;
}

const fallbackAnnotations = mediaAnnotations.length === 0
  ? fallbackAnnotationsFromTargets(imageTargets, candidateRows)
  : [];
const effectiveMediaAnnotations = mediaAnnotations.length > 0 ? mediaAnnotations : fallbackAnnotations;

const strictMediaAnnotations = webhookPayload.media_annotation_mode === 'strict' || webhookPayload.media_annotation_required === true;
const minExpected = Math.max(0, Number(webhookPayload.media_annotation_min_expected || 0));
if (strictMediaAnnotations && minExpected > 0 && effectiveMediaAnnotations.length < minExpected) {
  qualityWarnings.push(`Missing media_annotations (expected>=${minExpected}, got=${effectiveMediaAnnotations.length}, candidates=${candidateRows.length}, targets=${imageTargets.length}). Continuing in fallback mode.`);
}
if (fallbackAnnotations.length > 0) {
  qualityWarnings.push(`Generated ${fallbackAnnotations.length} fallback media_annotations from image_generation targets.`);
}
if (candidateRows.length > 0 && effectiveMediaAnnotations.length === 0) {
