function remapLegacyHomepageFieldKey(key) {
  if (typeof key !== 'string' || key.indexOf('.') === -1) return key;
  const [section, field] = key.split('.', 2);
  const sectionMap = {
    intro: 'service_intro',
    services: 'service_details',
    about: 'benefits',
    testimonials: 'trust_reviews'
  };
  const fieldMap = {
    hero_cta_primary: 'cta_primary_override',
    hero_cta_secondary: 'cta_secondary_override',
    cta_primary: 'cta_primary_override',
    cta_secondary: 'cta_secondary_override'
  };
  const mappedSection = sectionMap[section] || section;
  const mappedField = fieldMap[field] || field;
  return `${mappedSection}.${mappedField}`;
}

let remapCount = 0;
const normalizedUpdates = Array.isArray($json?.updates)
  ? $json.updates.map((update) => {
      if (!update || typeof update !== 'object') return update;
      const target = String(update.target || '');
      const id = String(update.id || '');
      if (target !== 'options' || id !== 'homepage' || !update.fields || typeof update.fields !== 'object') {
        return update;
      }
      const nextFields = {};
      for (const rawKey of Object.keys(update.fields)) {
        const mappedKey = remapLegacyHomepageFieldKey(rawKey);
        if (mappedKey !== rawKey) remapCount += 1;
        nextFields[mappedKey] = update.fields[rawKey];
      }
      return { ...update, fields: nextFields };
    })
  : $json?.updates;

if (remapCount > 0) {
  qualityWarnings.push(`Normalized ${remapCount} legacy homepage field keys before callback.`);
}

const identityBusiness = String(webhookPayload.business_name || webhookPayload.business?.name || '').trim();
const identityCity = String(webhookPayload.city_region || webhookPayload.business?.primary_city || webhookPayload.business?.address?.city || '').trim();
const identityNiche = String(webhookPayload.niche || webhookPayload.business?.niche || '').trim();
const identityNicheSlug = String(webhookPayload.niche_slug || webhookPayload.business?.niche_slug || '').trim();

const callbackBodyObj = {
  ...$json,
  business_name: $json.business_name || identityBusiness,
  city_region: $json.city_region || identityCity,
  niche: $json.niche || identityNiche,
  niche_slug: $json.niche_slug || identityNicheSlug,
  updates: normalizedUpdates,
  job_id: jobId,
  request_id: requestId,
  callback_url: callbackUrl,
  media_annotations: effectiveMediaAnnotations,
  quality_warnings: Array.from(new Set(qualityWarnings))
};

return [{
  json: {
    ...callbackBodyObj,
    callback_payload: { payload: JSON.stringify(callbackBodyObj) },
    callback_auth_header: authHeader
  }
}];

const allItems = $input.all();
if (!allItems.length) {
  return [{ json: { ok: false, updates: [], error: 'No items for global completeness gate.', quality_warnings: ['No items for global completeness gate.'] } }];
}

const upstreamFailures = allItems
  .map(item => item?.json || {})
  .filter(j => j && j.ok === false);

const items = allItems.filter(item => item?.json?.ok !== false);
if (!items.length) {
  const warnings = upstreamFailures.map(f => {
    const pageType = f.page_type || 'unknown';
    const err = String(f.error || 'unknown_error');
    const detail = String(f.details || '').trim();
    return detail
      ? `Dropped blueprint page_type=${pageType}: ${err} (${detail})`
      : `Dropped blueprint page_type=${pageType}: ${err}`;
  });
  return [{ json: { ok: false, updates: [], error: 'All blueprint items failed before completeness checks.', quality_warnings: warnings.length ? warnings : ['All blueprint items failed before completeness checks'] } }];
}

const parseWarnings = upstreamFailures.map(f => {
  const pageType = f.page_type || 'unknown';
  const err = String(f.error || 'unknown_error');
  const detail = String(f.details || '').trim();
  return detail
    ? `Dropped blueprint page_type=${pageType}: ${err} (${detail})`
    : `Dropped blueprint page_type=${pageType}: ${err}`;
});

function wordCount(v) {
  const t = String(v || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  return t ? t.split(' ').length : 0;
}

function normalized(v) {
  return String(v || '').toLowerCase().replace(/\s+/g, ' ').trim();
}

const genericFlags = [
  'short overview of',
  'sample project created during site generation',
  'what to expect',
  'placeholder',
  'lorem ipsum'
];

function hasGenericText(text) {
  const n = normalized(text);
  return genericFlags.some(flag => n.includes(flag));
}

function toBool(value, fallback = false) {
  if (value === true || value === 1 || value === '1') return true;
  if (value === false || value === 0 || value === '0') return false;
  return fallback;
}

const webhook = $node['Webhook'].json || {};
const payload = webhook.body ?? webhook;
const manifestScopeMode = String(payload.generation_scope || '').trim().toLowerCase();
const scopeObject = (payload.generation_scope && typeof payload.generation_scope === 'object')
  ? payload.generation_scope
  : {};

const scope = manifestScopeMode === 'homepage_only'
  ? {
      homepage: true,
      services: false,
      service_areas: false,
      core_pages: false,
      blog_posts: false,
      projects: false
    }
  : {
      homepage: toBool(scopeObject.homepage, true),
      services: toBool(scopeObject.services, true),
      service_areas: toBool(scopeObject.service_areas, true),
      core_pages: toBool(scopeObject.core_pages, true),
      blog_posts: toBool(scopeObject.blog_posts, true),
      projects: toBool(scopeObject.projects, true)
    };

const warnings = [...parseWarnings];
const pageTypeCounts = {};

const homepageBlueprint = Array.isArray(payload.blueprints)
  ? payload.blueprints.find(bp => String(bp?.page || bp?.page_type || '').trim() === 'homepage')
  : null;
const homepagePostId = String(homepageBlueprint?.post_id || '').trim();

function looksLikeHomepageField(key) {
  const k = String(key || '').toLowerCase();
  return k.startsWith('hero') || k.startsWith('benefits') || k.startsWith('cta.') || k.startsWith('trust_') || k.startsWith('process') || k.startsWith('faq_accordion');
}

const isMergedPayload = items.length === 1
  && Array.isArray(items[0]?.json?.updates)
  && String(items[0]?.json?.page_type || '').trim() === '';

if (isMergedPayload) {
  const lfRepairRun = String(payload.run_phase || '').toLowerCase() === 'repair';
  const merged = items[0].json || {};
  const updates = Array.isArray(merged.updates) ? merged.updates : [];
  const faqTargets = Array.isArray(payload.blueprints)
    ? payload.blueprints.filter(bp => bp?.faq_target_count || bp?.faq_target_range)
    : [];
  const faqUpdates = updates.filter(update => String(update?.target || '') === 'faq');
  const faqEmbeddedInFields = updates.some(update => {
    const fields = update?.fields && typeof update.fields === 'object' ? update.fields : {};
    return Object.keys(fields).some(k => String(k).toLowerCase().includes('faq'));
  });
  if (faqTargets.length && faqUpdates.length === 0 && !faqEmbeddedInFields) {
    warnings.push('Blueprint FAQ targets present but no FAQ updates or FAQ-named fields in merged payload (check LLM output).');
  }
  const targetCounts = {};

  for (const update of updates) {
    const target = String(update?.target || 'unknown').trim() || 'unknown';
    targetCounts[target] = (targetCounts[target] || 0) + 1;
  }

  const homepageByOptions = updates.some(update =>
    String(update?.target || '') === 'options' && String(update?.id || '') === 'homepage'
  );

  const homepageByPostMeta = updates.some(update => {
    if (String(update?.target || '') !== 'post_meta') return false;
    const updateId = String(update?.id || '').trim();
    if (!updateId) return false;
    if (homepagePostId && updateId === homepagePostId) return true;
    const fields = update?.fields && typeof update.fields === 'object' ? update.fields : {};
    return Object.keys(fields).some(looksLikeHomepageField);
  });

  const homepageProduced = homepageByOptions || homepageByPostMeta;

  const nonHomepageNonFaqUpdates = updates.filter(update => {
    const target = String(update?.target || '');
    const id = String(update?.id || '');
    if (target === 'faq') return false;
    if (target === 'options' && id === 'homepage') return false;
    if (target === 'post_meta') {
      const updateId = String(update?.id || '').trim();
      if (homepagePostId && updateId === homepagePostId) return false;
    }
    return true;
  });

  if (scope.homepage && !homepageProduced && !lfRepairRun) {
    warnings.push('Scope mismatch: homepage enabled but no homepage updates detected.');
  }

  if ((scope.services || scope.service_areas || scope.core_pages || scope.blog_posts || scope.projects)
      && nonHomepageNonFaqUpdates.length === 0) {
    warnings.push(`Scope mismatch: non-homepage pages requested but merged updates only include homepage/faq. update_targets=${JSON.stringify(targetCounts)}`);
  }

  if (!updates.length) {
    merged.ok = false;
    merged.error = merged.error || 'Merged payload has zero updates (upstream parse/LLM failures).';
    warnings.push('Merged updates array is empty; inspect execution items before Deterministic FAQ for ok=false / Invalid JSON / Invalid payload.');
  }

  merged.quality_warnings = Array.isArray(merged.quality_warnings)
    ? Array.from(new Set(merged.quality_warnings.concat(warnings)))
    : warnings;
  merged.page_type_counts = merged.page_type_counts || {};
  merged.update_target_counts = targetCounts;
  merged.scope_mismatch = warnings.some(w => String(w).startsWith('Scope mismatch:'));
  merged.parse_failed_count = upstreamFailures.length;
  merged.homepage_detected_via = homepageByOptions ? 'options' : (homepageByPostMeta ? 'post_meta' : 'none');
  return [{ json: merged }];
}

for (const item of items) {
  const j = item.json || {};
  const pageType = String(j.page_type || '').trim();
  if (pageType) {
    pageTypeCounts[pageType] = (pageTypeCounts[pageType] || 0) + 1;
  }

  if (!j.ok || !Array.isArray(j.updates) || !j.updates.length) {
    warnings.push(`Missing updates for page_type=${pageType || 'unknown'}`);
    continue;
  }

  let pageWords = 0;
  let hasPrimary = false;
  const primary = String(j?.meta?.primary_keyword || '').trim();

  for (const update of j.updates) {
    if (!update || !update.fields || typeof update.fields !== 'object') continue;
    for (const key of Object.keys(update.fields)) {
      const value = update.fields[key];
      if (typeof value !== 'string') continue;
      pageWords += wordCount(value);
      if (primary && normalized(value).includes(normalized(primary))) {
        hasPrimary = true;
      }
      if (hasGenericText(value)) {
        warnings.push(`Generic placeholder phrase found in ${pageType || 'unknown'} field ${key}`);
      }
    }
  }

  if (primary && !hasPrimary) {
    warnings.push(`Primary keyword missing in content body for ${pageType || 'unknown'}`);
  }

  const minWords = pageType === 'post' ? 450 : (pageType === 'homepage' ? 180 : 120);
  if (pageWords < minWords) {
    warnings.push(`Low content volume for ${pageType || 'unknown'} (${pageWords} words, min ${minWords})`);
  }
}

if (scope.homepage && !pageTypeCounts.homepage) {
  warnings.push('Scope mismatch: homepage enabled but no homepage blueprints were produced.');
}
if (scope.services && !pageTypeCounts.service) {
  warnings.push('Scope mismatch: services enabled but no service blueprints were produced.');
}
if (scope.service_areas && !pageTypeCounts.service_area) {
  warnings.push('Scope mismatch: service_areas enabled but no service_area blueprints were produced.');
}
if (scope.core_pages) {
  const required = ['about', 'contact'];
  for (const type of required) {
    if (!pageTypeCounts[type]) {
      warnings.push(`Scope mismatch: core_pages enabled but missing page_type=${type}`);
    }
  }
}
if (scope.blog_posts) {
  const blogCount = pageTypeCounts.post || 0;
  if (blogCount < 5) {
    warnings.push(`Scope mismatch: blog_posts enabled but only ${blogCount} blog blueprints were produced (expected at least 5).`);
  }
}

for (const item of items) {
  if (!item.json || typeof item.json !== 'object') item.json = {};
  const existing = Array.isArray(item.json.quality_warnings) ? item.json.quality_warnings : [];
  item.json.quality_warnings = Array.from(new Set(existing.concat(warnings)));
  item.json.page_type_counts = pageTypeCounts;
  item.json.scope_mismatch = warnings.some(w => String(w).startsWith('Scope mismatch:'));
  item.json.parse_failed_count = upstreamFailures.length;
}

return items;

// Cache blueprint input for retries (canonical + alias maps, per-request invalidation)
const data = $getWorkflowStaticData('global');

function normalizeKeySegment(s) {
  return String(s ?? '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .replace(/:/g, '-');
}

const items = $input.all();
