function ensureCacheMaps() {
  if (!data.blueprint_cache_by_id || typeof data.blueprint_cache_by_id !== 'object') data.blueprint_cache_by_id = {};
  if (!data.blueprint_cache_aliases || typeof data.blueprint_cache_aliases !== 'object') data.blueprint_cache_aliases = {};
  if (!data.blueprint_cache_alias_collisions || typeof data.blueprint_cache_alias_collisions !== 'object') data.blueprint_cache_alias_collisions = {};
  if (!data.blueprint_cache || typeof data.blueprint_cache !== 'object') data.blueprint_cache = {};
}

function registerAlias(aliasKey, cid) {
  if (!aliasKey || !cid) return;
  const prev = data.blueprint_cache_aliases[aliasKey];
  if (prev !== undefined && prev !== cid) {
    data.blueprint_cache_alias_collisions[aliasKey] = true;
  }
  data.blueprint_cache_aliases[aliasKey] = cid;
}

for (const item of items) {
  const json = item.json || {};
  const requestId = String(json.request_id || '');
  const blueprintIndex = json.blueprint_index;
  const canonical_id = `${requestId}:${blueprintIndex ?? ''}`;

  if (data.last_request_id !== requestId) {
    data.blueprint_cache_by_id = {};
    data.blueprint_cache_aliases = {};
    data.blueprint_cache_alias_collisions = {};
    data.retry_fallback_cache = {};
    data.blueprint_cache = {};
    data.last_request_id = requestId;
  }

  ensureCacheMaps();

  if (canonical_id) {
    data.blueprint_cache_by_id[canonical_id] = json;
    data.blueprint_cache[canonical_id] = json;
    registerAlias(canonical_id, canonical_id);

    const normPageType = normalizeKeySegment(json.page_type);
    const postRaw = json.blueprint?.post_id ?? json.post_id;
    const postIdStr = postRaw != null && String(postRaw).trim() !== '' ? String(postRaw).trim() : '';
    if (postIdStr) {
      registerAlias(`${requestId}:${normPageType}:post:${postIdStr}`, canonical_id);
    }

    const meta = json.meta && typeof json.meta === 'object' ? json.meta : {};
    const primaryKeyword = meta.primary_keyword || json.primary_keyword;
    const normPk = normalizeKeySegment(primaryKeyword);
    if (normPageType && normPk) {
      registerAlias(`${requestId}:${normPageType}:${normPk}`, canonical_id);
    }
  }

  out.push({ json });
}

return out;

// Decide which pages need an LLM retry
const data = $getWorkflowStaticData('global') || {};
const aliases = data.blueprint_cache_aliases || {};
const collisions = data.blueprint_cache_alias_collisions || {};
if (!data.retry_fallback_cache || typeof data.retry_fallback_cache !== 'object') {
  data.retry_fallback_cache = {};
}

function normalizeKeySegment(s) {
  return String(s ?? '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .replace(/:/g, '-');
}

function isSevere(w) {
  return /duplicate|repeated|generic|in your area|city repeated|is not registered|is not allowed|placeholder token|PRIMARY_KEYWORD|BUSINESS_NAME|CITY_REGION|NICHE_TOKEN|low content volume|Missing primary keyword/i.test(String(w || ""));
}

const items = $input.all();

return items.map(item => {
  const j = item.json || {};
  const warnings = Array.isArray(j.quality_warnings) ? j.quality_warnings : [];
  const retry_count = typeof j.retry_count === "number" ? j.retry_count : 0;
  const max_retries = 2;
  const has_severe = warnings.some(isSevere);
  const base_needs_retry = has_severe && retry_count < max_retries;

  let needs_retry = base_needs_retry;
  let retry_cache_key = '';
  let retry_cache_id = '';
  const extraWarnings = [];

  if (base_needs_retry) {
    const requestId = String(j.request_id || '').trim();
    const blueprintIndex = j.blueprint_index;
    const meta = j.meta && typeof j.meta === 'object' ? j.meta : {};
    let primary_keyword = '';
    if (meta.primary_keyword != null && String(meta.primary_keyword).trim() !== '') {
      primary_keyword = String(meta.primary_keyword).trim();
    } else if (j.primary_keyword != null && String(j.primary_keyword).trim() !== '') {
      primary_keyword = String(j.primary_keyword).trim();
    }
    const normPageType = normalizeKeySegment(j.page_type);
    const postRaw = j.blueprint?.post_id ?? j.post_id;
    const postIdStr = postRaw != null && String(postRaw).trim() !== '' ? String(postRaw).trim() : '';
    const normPk = normalizeKeySegment(primary_keyword);

    const candidates = [];
    const indexPart = blueprintIndex !== undefined && blueprintIndex !== null ? String(blueprintIndex) : '';
    if (requestId && indexPart.trim() !== '') {
      candidates.push(`${requestId}:${blueprintIndex}`);
    }
    if (requestId && normPageType && postIdStr) {
      candidates.push(`${requestId}:${normPageType}:post:${postIdStr}`);
    }
    if (requestId && normPageType && normPk) {
      candidates.push(`${requestId}:${normPageType}:${normPk}`);
    }

    const hitCollision = candidates.some(k => collisions[k]);
    if (hitCollision) {
      needs_retry = false;
      extraWarnings.push('Retry skipped: alias collision for cache key.');
    } else {
      const resolved = [];
      for (const k of candidates) {
        const cid = aliases[k];
        if (cid !== undefined && cid !== null && String(cid) !== '') {
          resolved.push(String(cid));
        }
      }
      const unique = [...new Set(resolved)];
      if (unique.length > 1) {
        needs_retry = false;
        extraWarnings.push('Retry skipped: ambiguous cache key match.');
      } else if (unique.length === 0) {
        needs_retry = false;
        extraWarnings.push('Retry skipped: missing cached blueprint for page_type + primary_keyword.');
      } else {
        retry_cache_id = unique[0];
        for (const k of candidates) {
          if (String(aliases[k] || '') === retry_cache_id) {
            retry_cache_key = k;
            break;
          }
        }
        data.retry_fallback_cache[retry_cache_id] = item.json;
        needs_retry = true;
      }
    }
  }

  const allWarnings = Array.from(new Set([...warnings, ...extraWarnings]));

  const out = {
    ...j,
    needs_retry,
    retry_count,
    quality_warnings: allWarnings,
    retry_instructions: needs_retry && allWarnings.length
      ? "Rewrite this entire page in valid JSON. Fix: " + allWarnings.join(" | ") + " | Never output machine tokens like PRIMARY_KEYWORD, BUSINESS_NAME, or CITY_REGION as visible text—use natural language with the real business name, city, and services from the blueprint. Meet word-depth requirements. Include required FAQ target updates when the blueprint specifies faq_target_count or faq_target_range."
      : "",
  };
  if (needs_retry && retry_cache_id) {
    out.retry_cache_key = retry_cache_key;
    out.retry_cache_id = retry_cache_id;
  }
  return { json: out };
});

const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const updatesEmpty = !Array.isArray(j.updates) || j.updates.length === 0;
  if (!updatesEmpty && j.needs_retry) {
    const existing = Array.isArray(j.quality_warnings) ? j.quality_warnings : [];
    j.quality_warnings = Array.from(new Set(existing.concat([
      'Retry skipped: content already generated despite quality warnings.'
    ])));
    j.needs_retry = false;
    j.retry_instructions = '';
  }
  return { json: j };
});

// Build retry input from cached blueprint (retry_cache_key first, then fallbacks)
const data = $getWorkflowStaticData('global') || {};
const aliases = data.blueprint_cache_aliases || {};
const collisions = data.blueprint_cache_alias_collisions || {};
const byId = data.blueprint_cache_by_id || {};
const fallbackCache = data.retry_fallback_cache || {};

function normalizeKeySegment(s) {
  return String(s ?? '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .replace(/:/g, '-');
}

const j = $json || {};
const requestId = String(j.request_id || '').trim();
const blueprintIndex = j.blueprint_index;
const meta = j.meta && typeof j.meta === 'object' ? j.meta : {};
let primary_keyword = '';
if (meta.primary_keyword != null && String(meta.primary_keyword).trim() !== '') {
  primary_keyword = String(meta.primary_keyword).trim();
} else if (j.primary_keyword != null && String(j.primary_keyword).trim() !== '') {
  primary_keyword = String(j.primary_keyword).trim();
}
const normPageType = normalizeKeySegment(j.page_type);
const postRaw = j.blueprint?.post_id ?? j.post_id;
const postIdStr = postRaw != null && String(postRaw).trim() !== '' ? String(postRaw).trim() : '';
const normPk = normalizeKeySegment(primary_keyword);

const seen = new Set();
const keysToTry = [];
function addKey(k) {
  const ks = k != null ? String(k).trim() : '';
  if (!ks || seen.has(ks)) return;
  seen.add(ks);
  keysToTry.push(ks);
}

if (j.retry_cache_key != null && String(j.retry_cache_key).trim() !== '') {
  addKey(j.retry_cache_key);
}
const indexPart = blueprintIndex !== undefined && blueprintIndex !== null ? String(blueprintIndex) : '';
if (requestId && indexPart.trim() !== '') {
  addKey(`${requestId}:${blueprintIndex}`);
}
if (requestId && normPageType && postIdStr) {
  addKey(`${requestId}:${normPageType}:post:${postIdStr}`);
}
if (requestId && normPageType && normPk) {
  addKey(`${requestId}:${normPageType}:${normPk}`);
}

function resolveKey(aliasKey) {
  if (!aliasKey || collisions[aliasKey]) return null;
  const cid = aliases[aliasKey];
  if (cid === undefined || cid === null || String(cid) === '') return null;
  const canonical = String(cid);
  const base = byId[canonical];
  if (!base || typeof base !== 'object') return null;
  return { canonical, base };
}

let resolved = null;
let matchedKey = '';
for (const k of keysToTry) {
  resolved = resolveKey(k);
  if (resolved) {
    matchedKey = k;
    break;
  }
}

const preservedRetryCacheId = j.retry_cache_id != null && String(j.retry_cache_id).trim() !== ''
  ? String(j.retry_cache_id).trim()
  : '';

if (resolved) {
  const { canonical, base } = resolved;
  const retry_count = (j.retry_count ?? base.retry_count ?? 0) + 1;
  const out = {
    ...base,
    retry_instructions: j.retry_instructions || 'Fix quality warnings and ensure uniqueness',
    retry_count,
    retry_cache_miss: false,
  };
  out.retry_cache_id = preservedRetryCacheId || canonical;
  if (matchedKey) out.retry_cache_key = matchedKey;
  return [{ json: out }];
}

const missId = preservedRetryCacheId;
const fb = missId && fallbackCache[missId] && typeof fallbackCache[missId] === 'object'
  ? fallbackCache[missId]
  : null;

if (fb) {
  const warnMsg = 'Retry cache miss: using stored original output.';
  const qw = Array.isArray(fb.quality_warnings) ? [...fb.quality_warnings] : [];
  if (!qw.includes(warnMsg)) qw.push(warnMsg);
  return [{
    json: {
      ...fb,
      needs_retry: false,
      retry_cache_miss: true,
      retry_instructions: '',
      quality_warnings: qw,
      ...(missId ? { retry_cache_id: missId } : {}),
    },
  }];
}

const missWarnings = Array.isArray(j.quality_warnings) ? [...j.quality_warnings] : [];
missWarnings.push('Retry cache miss: fallback not found; using current item.');
return [{
  json: {
    ...j,
    needs_retry: false,
    retry_cache_miss: true,
    retry_instructions: '',
    quality_warnings: missWarnings,
    ...(missId ? { retry_cache_id: missId } : {}),
  },
}];

